    const state = {
      dayIndex: 0,
      kind: 'all',
      query: ''
    };

    const icons = {
      location: `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
          <path d="M12 21s-6-4.4-6-10a6 6 0 1 1 12 0c0 5.6-6 10-6 10Z"></path>
          <circle cx="12" cy="11" r="2.4"></circle>
        </svg>`,
      details: `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
          <path d="M4 6h16"></path>
          <path d="M4 12h16"></path>
          <path d="M4 18h10"></path>
        </svg>`
    };

    function escapeHtml(value) {
      return String(value)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
    }

    function normalize(value) {
      return String(value || '')
        .toLowerCase()
        .replace(/ё/g, 'е')
        .replace(/\s+/g, ' ')
        .trim();
    }

    function pluralActivities(n) {
      const abs = Math.abs(n) % 100;
      if (abs >= 11 && abs <= 14) return 'активностей';
      const last = abs % 10;
      if (last === 1) return 'активность';
      if (last >= 2 && last <= 4) return 'активности';
      return 'активностей';
    }

    function buildSearchIndex(event) {
      return normalize([
        event.kind,
        event.label,
        event.title,
        ...(event.extra_lines || []),
        ...(event.locations || []),
        ...(event.groups || [])
      ].join(' '));
    }

    function filteredEvents(day) {
      const query = normalize(state.query);
      return day.slots.map(slot => {
        const events = slot.events.filter(event => {
          const kindMatch = state.kind === 'all' || normalize(event.kind) === normalize(state.kind);
          const queryMatch = !query || buildSearchIndex(event).includes(query);
          return kindMatch && queryMatch;
        });
        return { ...slot, events };
      }).filter(slot => slot.events.length);
    }

    function renderGlobalStats() {
      const days = scheduleData.length;
      const activities = scheduleData.reduce((sum, day) => sum + day.activity_count, 0);
      const slots = scheduleData.reduce((sum, day) => sum + day.slot_count, 0);
      const audiences = [...new Set(scheduleData.map(day => day.audience))].join(' • ');

      document.getElementById('globalStats').innerHTML = `
        <div class="mini-card">
          <div class="label">Дней в расписании</div>
          <strong>${days}</strong>
        </div>
        <div class="mini-card">
          <div class="label">Всего карточек активностей</div>
          <strong>${activities}</strong>
        </div>
        <div class="mini-card">
          <div class="label">Временных слотов</div>
          <strong>${slots}</strong>
        </div>
        <div class="mini-card">
          <div class="label">Аудитория</div>
          <strong style="font-size:1.05rem; line-height:1.3">${escapeHtml(audiences)}</strong>
        </div>
      `;
    }

    function renderDayTabs() {
      const container = document.getElementById('dayTabs');
      container.innerHTML = scheduleData.map((day, index) => `
        <button class="${index === state.dayIndex ? 'active' : ''}" data-day-index="${index}">
          ${escapeHtml(day.date)}
        </button>
      `).join('');

      container.querySelectorAll('button').forEach(button => {
        button.addEventListener('click', () => {
          state.dayIndex = Number(button.dataset.dayIndex);
          renderApp();
        });
      });
    }

    function renderKindFilters() {
      const allKinds = ['all', ...Array.from(new Set(scheduleData.flatMap(day =>
        day.slots.flatMap(slot => slot.events.map(event => event.kind))
      )))];

      const labels = {
        all: 'Все',
        'Площадка': 'Площадки',
        'Экскурсия': 'Экскурсии',
        'Регистрация': 'Регистрация',
        'Открытие': 'Открытие',
        'Перерыв': 'Перерыв',
        'Квест': 'Квест',
        'Активность': 'Другое'
      };

      const container = document.getElementById('kindFilters');
      container.innerHTML = allKinds.map(kind => `
        <button class="${state.kind === kind ? 'active' : ''}" data-kind="${escapeHtml(kind)}">
          ${escapeHtml(labels[kind] || kind)}
        </button>
      `).join('');

      container.querySelectorAll('button').forEach(button => {
        button.addEventListener('click', () => {
          state.kind = button.dataset.kind;
          renderApp();
        });
      });
    }

    function cardMarkup(event) {
      const badges = [
        event.kind ? `<span class="badge primary">${escapeHtml(event.kind)}</span>` : '',
        event.label ? `<span class="badge">${escapeHtml(event.label)}</span>` : ''
      ].join('');

      const detailsBlock = (event.extra_lines && event.extra_lines.length)
        ? `
          <div class="meta-block">
            <div class="meta-title">Детали</div>
            <ul class="meta-list">
              ${event.extra_lines.map(line => `<li>${icons.details}<span>${escapeHtml(line)}</span></li>`).join('')}
            </ul>
          </div>`
        : '';

      const locationsBlock = (event.locations && event.locations.length)
        ? `
          <div class="meta-block">
            <div class="meta-title">Место</div>
            <ul class="meta-list">
              ${event.locations.map(item => `<li>${icons.location}<span>${escapeHtml(item).replace(/\n/g, '<br>')}</span></li>`).join('')}
            </ul>
          </div>`
        : '';

      const groupsBlock = (event.groups && event.groups.length)
        ? `
          <div class="meta-block">
            <div class="meta-title">Группы</div>
            <div class="group-list">
              ${event.groups.map(group => `<span class="group-chip">${escapeHtml(group)}</span>`).join('')}
            </div>
          </div>`
        : '';

      return `
        <article class="card">
          <div class="card-head">
            <div class="badges">${badges}</div>
          </div>
          <h3>${escapeHtml(event.title || event.label || event.kind)}</h3>
          <div class="meta">
            ${detailsBlock}
            ${locationsBlock}
            ${groupsBlock}
          </div>
        </article>
      `;
    }

    function renderDaySummary(day, slots) {
      const visibleActivities = slots.reduce((sum, slot) => sum + slot.events.length, 0);
      const firstTime = slots.length ? slots[0].time : '—';
      const lastTime = slots.length ? slots[slots.length - 1].time : '—';

      document.getElementById('daySummary').innerHTML = `
        <div class="summary-chip"><strong>${escapeHtml(day.audience)}</strong><span>Аудитория дня</span></div>
        <div class="summary-chip"><strong>${visibleActivities}</strong><span>Активностей по текущим фильтрам</span></div>
        <div class="summary-chip"><strong>${slots.length}</strong><span>Временных блоков</span></div>
        <div class="summary-chip"><strong>${escapeHtml(firstTime)}</strong><span>Старт дня</span></div>
        <div class="summary-chip"><strong>${escapeHtml(lastTime)}</strong><span>Последний слот</span></div>
      `;
    }

    function renderTimeline(day, slots) {
      const container = document.getElementById('timeline');

      if (!slots.length) {
        container.innerHTML = `
          <div class="empty">
            <strong style="display:block; margin-bottom:8px; font-size:1.08rem; color:var(--text)">Ничего не найдено</strong>
            Попробуйте сменить фильтр или очистить поисковый запрос.
          </div>
        `;
        return;
      }

      container.innerHTML = slots.map(slot => `
        <section class="slot">
          <aside class="slot-time">
            <span class="time">${escapeHtml(slot.time)}</span>
            <span class="count">${slot.events.length} ${pluralActivities(slot.events.length)}</span>
          </aside>
          <div class="cards">
            ${slot.events.map(cardMarkup).join('')}
          </div>
        </section>
      `).join('');
    }

    function renderApp() {
      const day = scheduleData[state.dayIndex];
      const slots = filteredEvents(day);

      document.getElementById('dayTitle').textContent = day.date;
      document.getElementById('audienceBadge').textContent = day.audience;

      renderDayTabs();
      renderKindFilters();
      renderDaySummary(day, slots);
      renderTimeline(day, slots);
    }

    document.getElementById('searchInput').addEventListener('input', (event) => {
      state.query = event.target.value;
      renderApp();
    });

    renderGlobalStats();
    renderApp();
